import { useCallback } from 'react';
// Global cooldown state - tüm component'ler arasında paylaşılır
let globalCooldown = false;
let cooldownTimeout = null;
/**
 * Global cooldown hook - Tüm mesaj gönderimlerini kontrol eder
 * @param delay - Bekleme süresi (milisaniye)
 * @returns Cooldown kontrol fonksiyonu
 */
export const useGlobalCooldown = (delay = 3000) => {
    const canSend = useCallback(() => {
        return !globalCooldown;
    }, []);
    const startCooldown = useCallback(() => {
        if (globalCooldown)
            return false; // Zaten cooldown aktif
        globalCooldown = true;
        // Önceki timeout'u temizle
        if (cooldownTimeout) {
            clearTimeout(cooldownTimeout);
        }
        // Yeni cooldown başlat
        cooldownTimeout = setTimeout(() => {
            globalCooldown = false;
        }, delay);
        return true; // Cooldown başlatıldı
    }, [delay]);
    const getRemainingTime = useCallback(() => {
        // Cooldown aktif değilse 0 döndür
        if (!globalCooldown)
            return 0;
        // Kalan süreyi hesapla (yaklaşık)
        return delay;
    }, [delay]);
    return {
        canSend,
        startCooldown,
        getRemainingTime,
        isOnCooldown: globalCooldown
    };
};
/**
 * Global cooldown state'ini sıfırla (test için)
 */
export const resetGlobalCooldown = () => {
    globalCooldown = false;
    if (cooldownTimeout) {
        clearTimeout(cooldownTimeout);
        cooldownTimeout = null;
    }
};
