/**
 * API Configuration Service
 * Environment-based API URL yönetimi
 * Mevcut config.js yapısı ile uyumlu
 */
// Environment-based configuration
const getAPIConfig = () => {
    // Development için sabit local URL - webpack build sırasında değiştirilecek
    const baseUrl = 'http://127.0.0.1:8000';
    return {
        BASE_URL: baseUrl,
        TIMEOUT: parseInt(process.env.REACT_APP_API_TIMEOUT || '10000'),
        ENDPOINTS: {
            CHAT: '/api/chat',
            CAMPAIGNS: '/api/campaigns',
            FAQS: '/api/faqs',
            PRODUCTS: '/api/products',
            WIDGET_CUSTOMIZATION: '/api/widget-customization',
            FEEDBACK: '/api/feedback',
            PRODUCT_CLICK: '/api/product-click',
            CARGO_TRACKING: '/api/cargo-tracking',
            // Token Management Endpoints
            ADD_TOKEN: '/api/add-token',
            EXHAUST_TOKEN: '/api/exhaust-token',
            // Subscription Endpoints
            USAGE: '/api/subscription/usage',
            PLANS: '/api/subscription/plans',
            BILLING_HISTORY: '/api/subscription/billing-history'
        },
        DEFAULT_AI_NAME: process.env.REACT_APP_DEFAULT_AI_NAME || 'ConvState AI',
        DEFAULT_WELCOME_MESSAGE: process.env.REACT_APP_DEFAULT_WELCOME_MESSAGE || 'Merhaba ben Kadir, senin dijital asistanınım. Sana nasıl yardımcı olabilirim?',
        SESSION_STORAGE_KEY: 'chat_session_id',
        MAX_PRODUCTS_TO_SHOW: 6,
        PRODUCT_IMAGE_PATH: baseUrl + '/imgs/',
        TYPING_DELAY: 1000,
        MAX_MESSAGE_LENGTH: 1000,
        ENABLE_TTS: process.env.REACT_APP_ENABLE_TTS === 'true',
        ENABLE_PRODUCT_RECOMMENDATIONS: process.env.REACT_APP_ENABLE_PRODUCT_RECOMMENDATIONS === 'true',
        ENABLE_CAMPAIGN_TAB: process.env.REACT_APP_ENABLE_CAMPAIGN_TAB === 'true',
        ENABLE_FAQ_TAB: process.env.REACT_APP_ENABLE_FAQ_TAB === 'true'
    };
};
// Global config instance
export const API_CONFIG = getAPIConfig();
// Helper functions - mevcut config.js ile uyumlu
export const getConfigValue = (key) => {
    return API_CONFIG[key];
};
export const buildApiUrl = (endpoint) => {
    return API_CONFIG.BASE_URL + endpoint;
};
export const getApiEndpoint = (endpoint) => {
    return API_CONFIG.ENDPOINTS[endpoint];
};
