/**
 * Browser UUID Service
 * Otomatik UUID oluşturma ve persistence yönetimi
 */
export class UuidService {
    constructor() {
        this.config = {
            prefix: 'browser_',
            storageKey: 'convstateai_browser_uuid',
            expiryHours: 72 // 72 saat
        };
    }
    static getInstance() {
        if (!UuidService.instance) {
            UuidService.instance = new UuidService();
        }
        return UuidService.instance;
    }
    /**
     * Browser UUID'yi al veya oluştur
     */
    getBrowserUuid() {
        try {
            // LocalStorage'dan mevcut UUID'yi kontrol et
            const stored = this.getStoredUuid();
            if (stored && this.isUuidValid(stored)) {
                // //console.log('Using existing browser UUID:', stored.uuid);
                return stored.uuid;
            }
            // Yeni UUID oluştur
            const newUuid = this.generateUuid();
            this.storeUuid(newUuid);
            // //console.log('Generated new browser UUID:', newUuid);
            return newUuid;
        }
        catch (error) {
            // Error getting browser UUID
            // Fallback: basit UUID oluştur
            return this.generateUuid();
        }
    }
    /**
     * UUID oluştur
     */
    generateUuid() {
        const timestamp = Date.now();
        const random = Math.random().toString(36).substr(2, 9);
        const browserInfo = this.getBrowserFingerprint();
        return `${this.config.prefix}${timestamp}_${random}_${browserInfo}`;
    }
    /**
     * Browser fingerprint oluştur (basit)
     */
    getBrowserFingerprint() {
        try {
            const canvas = document.createElement('canvas');
            const ctx = canvas.getContext('2d');
            if (ctx) {
                ctx.textBaseline = 'top';
                ctx.font = '14px Arial';
                ctx.fillText('Browser fingerprint', 2, 2);
            }
            const fingerprint = [
                navigator.userAgent,
                navigator.language,
                window.screen.width + 'x' + window.screen.height,
                new Date().getTimezoneOffset(),
                canvas.toDataURL().slice(-10) // Son 10 karakter
            ].join('|');
            // Hash oluştur (basit)
            let hash = 0;
            for (let i = 0; i < fingerprint.length; i++) {
                const char = fingerprint.charCodeAt(i);
                hash = ((hash << 5) - hash) + char;
                hash = hash & hash; // 32bit integer'a çevir
            }
            return Math.abs(hash).toString(36).substr(0, 8);
        }
        catch (error) {
            // Browser fingerprint failed, using fallback
            return Math.random().toString(36).substr(2, 8);
        }
    }
    /**
     * Stored UUID'yi al
     */
    getStoredUuid() {
        try {
            const stored = localStorage.getItem(this.config.storageKey);
            if (!stored)
                return null;
            const parsed = JSON.parse(stored);
            return {
                uuid: parsed.uuid,
                timestamp: parsed.timestamp
            };
        }
        catch (error) {
            // Error reading stored UUID
            return null;
        }
    }
    /**
     * UUID'yi kaydet
     */
    storeUuid(uuid) {
        try {
            const data = {
                uuid,
                timestamp: Date.now()
            };
            localStorage.setItem(this.config.storageKey, JSON.stringify(data));
        }
        catch (error) {
            // Error storing UUID
        }
    }
    /**
     * UUID'nin geçerli olup olmadığını kontrol et
     */
    isUuidValid(stored) {
        const now = Date.now();
        const expiryTime = this.config.expiryHours * 60 * 60 * 1000; // 72 saat
        const isValid = (now - stored.timestamp) < expiryTime;
        if (!isValid) {
            // //console.log('Browser UUID expired, generating new one');
        }
        return isValid;
    }
    /**
     * UUID'yi yenile (force refresh)
     */
    refreshUuid() {
        // //console.log('Refreshing browser UUID');
        const newUuid = this.generateUuid();
        this.storeUuid(newUuid);
        return newUuid;
    }
    /**
     * UUID'yi temizle
     */
    clearUuid() {
        try {
            localStorage.removeItem(this.config.storageKey);
            // //console.log('Browser UUID cleared');
        }
        catch (error) {
            // Error clearing UUID
        }
    }
    /**
     * UUID bilgilerini al
     */
    getUuidInfo() {
        const stored = this.getStoredUuid();
        if (!stored)
            return null;
        const created = new Date(stored.timestamp);
        const expires = new Date(stored.timestamp + (this.config.expiryHours * 60 * 60 * 1000));
        const isValid = this.isUuidValid(stored);
        return {
            uuid: stored.uuid,
            created,
            expires,
            isValid
        };
    }
    /**
     * Debug bilgileri - Production'da kaldırıldı
     */
    getDebugInfo() {
        // Production mode - no debug info
        return null;
    }
}
// Singleton instance export
export const uuidService = UuidService.getInstance();
