import { useReducer, useCallback } from 'react';
// Initial state
const initialState = {
    messages: [],
    isTyping: false,
    scrollToBottom: false,
    isSoundEnabled: false,
    isChatVisible: false,
    showCampaignTab: false,
    showFAQTab: false,
    isTabTransitioning: false,
    tabAvailability: {
        campaigns: false,
        faqs: false,
        loading: true
    },
    apiErrorMessages: [],
    isLimitExceeded: false
};
// Reducer function
function chatReducer(state, action) {
    switch (action.type) {
        case 'ADD_MESSAGE':
            return Object.assign(Object.assign({}, state), { messages: [...state.messages, action.payload], scrollToBottom: true });
        case 'SET_TYPING':
            return Object.assign(Object.assign({}, state), { isTyping: action.payload });
        case 'SET_SCROLL_TO_BOTTOM':
            return Object.assign(Object.assign({}, state), { scrollToBottom: action.payload });
        case 'TOGGLE_SOUND':
            return Object.assign(Object.assign({}, state), { isSoundEnabled: !state.isSoundEnabled });
        case 'SET_CHAT_VISIBLE':
            return Object.assign(Object.assign({}, state), { isChatVisible: action.payload });
        case 'SET_CAMPAIGN_TAB':
            return Object.assign(Object.assign({}, state), { showCampaignTab: action.payload, showFAQTab: false });
        case 'SET_FAQ_TAB':
            return Object.assign(Object.assign({}, state), { showFAQTab: action.payload, showCampaignTab: false });
        case 'SET_TAB_TRANSITIONING':
            return Object.assign(Object.assign({}, state), { isTabTransitioning: action.payload });
        case 'SET_TAB_AVAILABILITY':
            return Object.assign(Object.assign({}, state), { tabAvailability: Object.assign(Object.assign({}, state.tabAvailability), action.payload) });
        case 'ADD_API_ERROR':
            return Object.assign(Object.assign({}, state), { apiErrorMessages: [...state.apiErrorMessages, action.payload] });
        case 'REMOVE_API_ERROR':
            return Object.assign(Object.assign({}, state), { apiErrorMessages: state.apiErrorMessages.filter(msg => msg.id !== action.payload) });
        case 'SET_LIMIT_EXCEEDED':
            return Object.assign(Object.assign({}, state), { isLimitExceeded: action.payload });
        case 'CLEAR_MESSAGES':
            return Object.assign(Object.assign({}, state), { messages: [] });
        case 'RESET_STATE':
            return initialState;
        default:
            return state;
    }
}
// Custom hook
export const useChatState = () => {
    const [state, dispatch] = useReducer(chatReducer, initialState);
    // Action creators
    const addMessage = useCallback((message) => {
        dispatch({ type: 'ADD_MESSAGE', payload: message });
    }, []);
    const setTyping = useCallback((isTyping) => {
        dispatch({ type: 'SET_TYPING', payload: isTyping });
    }, []);
    const setScrollToBottom = useCallback((scrollToBottom) => {
        dispatch({ type: 'SET_SCROLL_TO_BOTTOM', payload: scrollToBottom });
    }, []);
    const toggleSound = useCallback(() => {
        dispatch({ type: 'TOGGLE_SOUND' });
    }, []);
    const setChatVisible = useCallback((isVisible) => {
        dispatch({ type: 'SET_CHAT_VISIBLE', payload: isVisible });
    }, []);
    const setCampaignTab = useCallback((show) => {
        dispatch({ type: 'SET_CAMPAIGN_TAB', payload: show });
    }, []);
    const setFAQTab = useCallback((show) => {
        dispatch({ type: 'SET_FAQ_TAB', payload: show });
    }, []);
    const setTabTransitioning = useCallback((isTransitioning) => {
        dispatch({ type: 'SET_TAB_TRANSITIONING', payload: isTransitioning });
    }, []);
    const setTabAvailability = useCallback((availability) => {
        dispatch({ type: 'SET_TAB_AVAILABILITY', payload: availability });
    }, []);
    const addApiError = useCallback((errorMessage) => {
        dispatch({ type: 'ADD_API_ERROR', payload: errorMessage });
    }, []);
    const removeApiError = useCallback((messageId) => {
        dispatch({ type: 'REMOVE_API_ERROR', payload: messageId });
    }, []);
    const setLimitExceeded = useCallback((isExceeded) => {
        dispatch({ type: 'SET_LIMIT_EXCEEDED', payload: isExceeded });
    }, []);
    const clearMessages = useCallback(() => {
        dispatch({ type: 'CLEAR_MESSAGES' });
    }, []);
    const resetState = useCallback(() => {
        dispatch({ type: 'RESET_STATE' });
    }, []);
    return {
        state,
        actions: {
            addMessage,
            setTyping,
            setScrollToBottom,
            toggleSound,
            setChatVisible,
            setCampaignTab,
            setFAQTab,
            setTabTransitioning,
            setTabAvailability,
            addApiError,
            removeApiError,
            setLimitExceeded,
            clearMessages,
            resetState
        }
    };
};
